import{_ as t,o as A,c as r,a2 as a}from"./chunks/framework.BbQrW5_t.js";const s="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",o="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",g="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",n="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",m="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",d="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",e="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",l="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",i="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",x="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",S=JSON.parse('{"title":"一次函数 — 广州中考典型试题与解析","description":"","frontmatter":{"title":"一次函数 — 广州中考典型试题与解析","date":"2026-07-04T00:00:00.000Z","tags":["一次函数","广州中考","压轴题","函数综合"]},"headers":[],"relativePath":"study/junior-math/exam/linear-function.md","filePath":"study/junior-math/exam/linear-function.md","lastUpdated":1783652711000}'),b={name:"study/junior-math/exam/linear-function.md"};function h(u,p,y,k,c,P){return A(),r("div",null,[...p[0]||(p[0]=[a('<h1 id="一次函数-—-广州中考典型试题与解析" tabindex="-1">一次函数 — 广州中考典型试题与解析 <a class="header-anchor" href="#一次函数-—-广州中考典型试题与解析" aria-label="Permalink to &quot;一次函数 — 广州中考典型试题与解析&quot;">​</a></h1><blockquote><p>一次函数是初中函数的起点，广州中考压轴题常涉及一次函数与几何综合，分值 10–12 分。</p><p>难度标注：⭐ 基础 | ⭐⭐ 中等 | ⭐⭐⭐ 较难 | ⭐⭐⭐⭐ 压轴</p></blockquote><hr><h2 id="案例-1-求一次函数解析式-⭐" tabindex="-1">案例 1：求一次函数解析式 ⭐ <a class="header-anchor" href="#案例-1-求一次函数解析式-⭐" aria-label="Permalink to &quot;案例 1：求一次函数解析式 ⭐&quot;">​</a></h2><p><img src="'+s+'" alt="案例1示意图"></p><p><strong>【题目】</strong> 已知一次函数 y = kx + b 的图象经过点 A(1, 3) 和点 B(3, 7)，求这个一次函数的解析式。</p><p><strong>【解析】</strong></p><p>将 A(1, 3) 代入 y = kx + b：</p><p>k + b = 3 …… θ</p><p>将 B(3, 7) 代入 y = kx + b：</p><p>3k + b = 7 …… Θ</p><p>Θ − θ：2k = 4，k = 2。</p><p>代入 θ：2 + b = 3，b = 1。</p><p>∴ 一次函数解析式为 <strong>y = 2x + 1</strong>。</p><p>验证：A(1, 3)：2 × 1 + 1 = 3 ✓；B(3, 7)：2 × 3 + 1 = 7 ✓。</p><p><strong>答：y = 2x + 1</strong></p><p><strong>【方法提炼】</strong> 待定系数法求一次函数解析式是中考必考基础题。步骤：(1) 设 y = kx + b；(2) 将已知点坐标代入，得二元一次方程组；(3) 解方程组求 k、b。两个独立条件确定一个一次函数。</p><hr><h2 id="案例-2-一次函数图象与性质-⭐" tabindex="-1">案例 2：一次函数图象与性质 ⭐ <a class="header-anchor" href="#案例-2-一次函数图象与性质-⭐" aria-label="Permalink to &quot;案例 2：一次函数图象与性质 ⭐&quot;">​</a></h2><p><img src="'+o+'" alt="案例2示意图"></p><p><strong>【题目】</strong> 已知一次函数 y = −2x + 4，回答下列问题：</p><p>（1）函数图象与 x 轴、y 轴的交点坐标分别是什么？</p><p>（2）当 x 取何值时，y &gt; 0？</p><p>（3）该函数图象经过哪些象限？</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 令 y = 0：−2x + 4 = 0，x = 2。与 x 轴交点为 (2, 0)。</p><p>令 x = 0：y = −2 × 0 + 4 = 4。与 y 轴交点为 (0, 4)。</p><p><strong>（2）</strong> y &gt; 0 即 −2x + 4 &gt; 0，−2x &gt; −4，x &lt; 2。</p><p>∴ 当 x &lt; 2 时，y &gt; 0。</p><p><strong>（3）</strong> k = −2 &lt; 0，b = 4 &gt; 0。</p><p>图象从左到右下降（k &lt; 0），过 y 轴正半轴（b &gt; 0），与 x 轴交于正半轴。</p><p>∴ 图象经过第一、二、四象限。</p><p><strong>答：（1）与 x 轴交点 (2, 0)，与 y 轴交点 (0, 4)；（2）x &lt; 2 时 y &gt; 0；（3）经过一、二、四象限</strong></p><p><strong>【方法提炼】</strong> 一次函数图象性质的核心是 k 和 b 的符号判断：k &gt; 0 图象上升，k &lt; 0 图象下降；b &gt; 0 过 y 轴正半轴，b &lt; 0 过 y 轴负半轴。求交点令 y = 0 或 x = 0 即可。象限判断口诀：“k 正 b 正一二三，k 正 b 负一三四，k 负 b 正一二四，k 负 b 负二三四”。</p><hr><h2 id="案例-3-一次函数与不等式-⭐⭐" tabindex="-1">案例 3：一次函数与不等式 ⭐⭐ <a class="header-anchor" href="#案例-3-一次函数与不等式-⭐⭐" aria-label="Permalink to &quot;案例 3：一次函数与不等式 ⭐⭐&quot;">​</a></h2><p><img src="'+g+'" alt="案例3示意图"></p><p><strong>【题目】</strong> 已知一次函数 y&amp;sub1; = 2x − 3 和 y&amp;sub2; = −x + 6。</p><p>（1）求两函数图象的交点坐标；</p><p>（2）当 x 取何值时，y&amp;sub1; &gt; y&amp;sub2;？</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 令 y&amp;sub1; = y&amp;sub2;：</p><p>2x − 3 = −x + 6</p><p>3x = 9</p><p>x = 3</p><p>y = 2 × 3 − 3 = 3</p><p>∴ 交点坐标为 (3, 3)。</p><p><strong>（2）</strong> y&amp;sub1; &gt; y&amp;sub2; 即 2x − 3 &gt; −x + 6：</p><p>3x &gt; 9，x &gt; 3。</p><p>从图象上看：在交点右侧，y&amp;sub1; 的图象在 y&amp;sub2; 的图象上方。</p><p>验证：x = 4 时，y&amp;sub1; = 5，y&amp;sub2; = 2，5 &gt; 2 ✓；x = 0 时，y&amp;sub1; = −3，y&amp;sub2; = 6，−3 &lt; 6 ✓。</p><p><strong>答：（1）交点坐标 (3, 3)；（2）x &gt; 3 时 y&amp;sub1; &gt; y&amp;sub2;</strong></p><p><strong>【方法提炼】</strong> 利用一次函数图象解不等式是数形结合的典型应用。交点把 x 轴分成两个区间，在每个区间内两函数的大小关系一致。口诀：“交点分界，上大下小”。也可以直接解不等式，但图象法更直观。</p><hr><h2 id="案例-4-一次函数实际应用-行程问题-⭐⭐" tabindex="-1">案例 4：一次函数实际应用（行程问题）⭐⭐ <a class="header-anchor" href="#案例-4-一次函数实际应用-行程问题-⭐⭐" aria-label="Permalink to &quot;案例 4：一次函数实际应用（行程问题）⭐⭐&quot;">​</a></h2><p><img src="'+n+'" alt="案例4示意图"></p><p><strong>【题目】</strong> 甲、乙两地相距 30 km，小明从甲地出发骑自行车去乙地，速度为 10 km/h；同时小红从乙地出发步行去甲地，速度为 5 km/h。</p><p>（1）分别写出两人与甲地的距离 y（km）与时间 x（h）的函数关系式；</p><p>（2）出发后几小时两人相遇？相遇点距甲地多远？</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 小明从甲地出发向乙地：</p><p>y&amp;sub1; = 10x（0 ≤ x ≤ 3）</p><p>小红从乙地出发向甲地，与甲地距离逐渐减小：</p><p>y&amp;sub2; = 30 − 5x（0 ≤ x ≤ 6）</p><p><strong>（2）</strong> 相遇时两人与甲地距离相等：</p><p>10x = 30 − 5x</p><p>15x = 30</p><p>x = 2</p><p>y = 10 × 2 = 20</p><p>∴ 出发后 2 小时两人相遇，相遇点距甲地 20 km。</p><p>验证：小明走了 2h × 10 = 20 km ✓，小红走了 2h × 5 = 10 km，30 − 10 = 20 km ✓。合计 20 + 10 = 30 km ✓。</p><p><strong>答：（1）y&amp;sub1; = 10x，y&amp;sub2; = 30 − 5x；（2）2 小时后相遇，距甲地 20 km</strong></p><p><strong>【方法提炼】</strong> 行程问题的函数建模关键：(1) 弄清起始位置和运动方向；(2) 相向而行，两人距离之和=总路程；(3) 同向而行，考虑追及问题。画出路程–时间图是解题利器。注意自变量取值范围。</p><hr><h2 id="案例-5-一次函数实际应用-利润问题-⭐⭐" tabindex="-1">案例 5：一次函数实际应用（利润问题）⭐⭐ <a class="header-anchor" href="#案例-5-一次函数实际应用-利润问题-⭐⭐" aria-label="Permalink to &quot;案例 5：一次函数实际应用（利润问题）⭐⭐&quot;">​</a></h2><p><img src="'+m+'" alt="案例5示意图"></p><p><strong>【题目】</strong> 某商店购进一批商品，固定成本为 500 元，每件商品的进价为 6 元，售价为 10 元。设销售 x 件商品。</p><p>（1）分别写出总成本 C（元）和总收入 R（元）关于 x 的函数关系式；</p><p>（2）至少销售多少件才能不亏本？</p><p>（3）若要获利不低于 1000 元，至少销售多少件？</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 总成本 = 固定成本 + 变动成本：</p><p>C = 500 + 6x（x ≥ 0）</p><p>总收入 = 售价 × 销量：</p><p>R = 10x（x ≥ 0）</p><p><strong>（2）</strong> 不亏本即 R ≥ C：</p><p>10x ≥ 500 + 6x</p><p>4x ≥ 500</p><p>x ≥ 125</p><p>∴ 至少销售 125 件才能不亏本。</p><p><strong>（3）</strong> 获利不低于 1000 元：</p><p>R − C ≥ 1000</p><p>10x − (500 + 6x) ≥ 1000</p><p>4x − 500 ≥ 1000</p><p>4x ≥ 1500</p><p>x ≥ 375</p><p>∴ 至少销售 375 件才能获利不低于 1000 元。</p><p><strong>答：（1）C = 500 + 6x，R = 10x；（2）至少 125 件；（3）至少 375 件</strong></p><p><strong>【方法提炼】</strong> 利润问题的函数建模：利润 = 收入 − 成本。固定成本是截距 b，单位变动成本影响斜率。盈亏平衡点是收入线与成本线的交点。不等式与一次函数结合是中考常考应用题类型。</p><hr><h2 id="案例-6-一次函数与三角形面积-⭐⭐⭐" tabindex="-1">案例 6：一次函数与三角形面积 ⭐⭐⭐ <a class="header-anchor" href="#案例-6-一次函数与三角形面积-⭐⭐⭐" aria-label="Permalink to &quot;案例 6：一次函数与三角形面积 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+d+'" alt="案例6示意图"></p><p><strong>【题目】</strong> 已知一次函数 y = −(3/4)x + 3 的图象与 x 轴交于点 A，与 y 轴交于点 B。</p><p>（1）求点 A、B 的坐标；</p><p>（2）求 ▵OAB 的面积；</p><p>（3）在直线 AB 上是否存在点 P，使 ▵OAP 的面积为 3？若存在，求出点 P 的坐标。</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 令 y = 0：−(3/4)x + 3 = 0，x = 4。A(4, 0)。</p><p>令 x = 0：y = 3。B(0, 3)。</p><p><strong>（2）</strong> S▵OAB = 1/2 × OA × OB = 1/2 × 4 × 3 = 6。</p><p><strong>（3）</strong> 设 P 在直线 AB 上，P(a, −3a/4 + 3)。</p><p>▵OAP 以 OA 为底，高为 |P 的纵坐标|：</p><p>S▵OAP = 1/2 × OA × |y&amp;subP;| = 1/2 × 4 × |−3a/4 + 3| = 2|−3a/4 + 3| = 3</p><p>|−3a/4 + 3| = 3/2</p><p>情况一：−3a/4 + 3 = 3/2，3a/4 = 3/2，a = 2。</p><p>P(2, −3/4 × 2 + 3) = (2, 3/2)。</p><p>情况二：−3a/4 + 3 = −3/2，3a/4 = 9/2，a = 6。</p><p>P(6, −3/4 × 6 + 3) = (6, −3/2)。</p><p>验证：P(2, 3/2)，S = 1/2 × 4 × 3/2 = 3 ✓；P(6, −3/2)，S = 1/2 × 4 × 3/2 = 3 ✓。</p><p><strong>答：（1）A(4, 0)，B(0, 3)；（2）S▵OAB = 6；（3）P(2, 3/2) 或 P(6, −3/2)</strong></p><p><strong>【方法提炼】</strong> 坐标系中求三角形面积，选择坐标轴上的边为底是关键技巧，此时高就是另一个顶点纵（横）坐标的绝对值。遇到绝对值要分类讨论，不要遗漏解。这是广州中考填空/解答题高频考点。</p><hr><h2 id="案例-7-分段函数应用-⭐⭐⭐" tabindex="-1">案例 7：分段函数应用 ⭐⭐⭐ <a class="header-anchor" href="#案例-7-分段函数应用-⭐⭐⭐" aria-label="Permalink to &quot;案例 7：分段函数应用 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+e+'" alt="案例7示意图"></p><p><strong>【题目】</strong> 某城市出租车收费标准如下：起步价 10 元（3 km 以内，含 3 km），超过 3 km 的部分每公里加收 2 元（不足 1 km 按 1 km 计）。</p><p>（1）写出车费 y（元）与行驶路程 x（km）的函数关系式（x 取整数）；</p><p>（2）小明乘车行驶了 8 km，应付车费多少元？</p><p>（3）若小明付了 24 元，他最多行驶了多少公里？</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 当 0 &lt; x ≤ 3 时，y = 10（起步价）；</p><p>当 x &gt; 3 时，y = 10 + 2(x − 3) = 2x + 4（x 取整数）。</p><p>即：</p><p>y = { 10, 0 &lt; x ≤ 3 { 2x + 4, x &gt; 3（x 为正整数）</p><p><strong>（2）</strong> x = 8 &gt; 3，y = 2 × 8 + 4 = 20 元。</p><p><strong>答：应付车费 20 元。</strong></p><p><strong>（3）</strong> y = 24，因为 24 &gt; 10，使用第二段：</p><p>2x + 4 = 24，2x = 20，x = 10。</p><p>验证：y = 2 × 10 + 4 = 24 ✓。</p><p><strong>答：最多行驶了 10 km。</strong></p><p><strong>【方法提炼】</strong> 分段函数是广州中考应用题常见题型。关键：(1) 准确确定分段点（此处为 x = 3）；(2) 每段分别建立函数关系式；(3) 求解时先判断属于哪一段再代入。注意自变量取值范围的标注不能遗漏。</p><hr><h2 id="案例-8-方案设计问题-⭐⭐⭐" tabindex="-1">案例 8：方案设计问题 ⭐⭐⭐ <a class="header-anchor" href="#案例-8-方案设计问题-⭐⭐⭐" aria-label="Permalink to &quot;案例 8：方案设计问题 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+l+'" alt="案例8示意图"></p><p><strong>【题目】</strong> 某学校需购买一批教具，有甲、乙两种方案：</p><p>方案甲：每套教具 20 元，另付运费 500 元；</p><p>方案乙：每套教具 30 元，免运费。</p><p>设购买 x 套教具（x 为正整数）。</p><p>（1）分别写出两种方案的费用 y（元）关于 x 的函数关系式；</p><p>（2）购买多少套时，两种方案费用相同？</p><p>（3）请你根据购买数量帮助学校选择最省钱的方案。</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 方案甲：y&amp;sub1; = 20x + 500</p><p>方案乙：y&amp;sub2; = 30x</p><p><strong>（2）</strong> 令 y&amp;sub1; = y&amp;sub2;：</p><p>20x + 500 = 30x</p><p>10x = 500</p><p>x = 50</p><p><strong>答：购买 50 套时费用相同。</strong></p><p><strong>（3）</strong> 当 x = 50 时，y&amp;sub1; = y&amp;sub2; = 1500 元，两种方案一样；</p><p>当 x &lt; 50 时，y&amp;sub1; − y&amp;sub2; = 500 − 10x &gt; 0，y&amp;sub1; &gt; y&amp;sub2;，选方案乙；</p><p>当 x &gt; 50 时，y&amp;sub1; − y&amp;sub2; = 500 − 10x &lt; 0，y&amp;sub1; &lt; y&amp;sub2;，选方案甲。</p><p>也可以从斜率角度理解：方案甲斜率小（20 &lt; 30），随着 x 增大，方案甲增长更慢，但截距大（500 &gt; 0），所以存在“交叉点”。</p><p><strong>答：购买不足 50 套选乙，恰好 50 套均可，超过 50 套选甲</strong></p><p><strong>【方法提炼】</strong> 方案设计题的核心是比较两个一次函数的大小关系。步骤：(1) 分别建立函数；(2) 求交点（费用相同点）；(3) 交点两侧分别比较。交点就是“临界点”，是决策的分界线。此类题是广州中考大题的常客。</p><hr><h2 id="案例-9-一次函数与动点面积最值-⭐⭐⭐⭐" tabindex="-1">案例 9：一次函数与动点面积最值 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-9-一次函数与动点面积最值-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 9：一次函数与动点面积最值 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+i+'" alt="案例9示意图"></p><p><strong>【题目】</strong> 如图，直线 y = −x + 4 与 x 轴交于点 A，与 y 轴交于点 B。点 P 在 x 轴的正半轴上运动，设 P(t, 0)（0 &lt; t &lt; 4）。</p><p>（1）求点 A、B 的坐标；</p><p>（2）当 P 在线段 OA 上运动时，设 ▵OBP 的面积为 S，求 S 关于 t 的函数关系式，并求 S 的最大值；</p><p>（3）过 P 作 PQ ⊥ x 轴交直线 AB 于 Q，当 t 为何值时，▵OPQ 的面积最大？最大面积是多少？</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 令 y = 0：−x + 4 = 0，x = 4。A(4, 0)。</p><p>令 x = 0：y = 4。B(0, 4)。</p><p><strong>（2）</strong> ▵OBP 以 OP = t 为底，OB = 4 为高：</p><p>S = 1/2 × t × 4 = 2t（0 &lt; t &lt; 4）</p><p>S 随 t 增大而增大，当 t → 4 时 S → 8。</p><p>但 t &lt; 4（P 不与 A 重合），所以 S 没有最大值（开区间）。</p><p>若题目允许 t = 4（P 与 A 重合），则 S&amp;submax; = 2 × 4 = 8。</p><p><strong>答：S = 2t，S&amp;submax; = 8（t = 4 时）</strong></p><p><strong>（3）</strong> P(t, 0)，Q 在直线 AB 上，Q(t, −t + 4)（0 &lt; t &lt; 4）。</p><p>▵OPQ 以 OP = t 为底，PQ = |−t + 4| = 4 − t 为高：</p><p>S&amp;subOPQ; = 1/2 × t × (4 − t) = −t²/2 + 2t = −1/2(t − 2)² + 2</p><p>当 t = 2 时，S&amp;subOPQ; 取最大值 2。</p><p>此时 P(2, 0)，Q(2, 2)，验证：S = 1/2 × 2 × 2 = 2 ✓。</p><p><strong>答：t = 2 时 ▵OPQ 面积最大，最大面积为 2</strong></p><p><strong>【方法提炼】</strong> 动点面积最值问题是广州中考压轴题的典型模型。核心方法：(1) 设动点参数 t，用 t 表示面积 S；(2) S 的表达式通常是二次函数 S = −at² + bt（a &gt; 0）；(3) 配方求最值 S = −a(t − b/2a)² + b²/4a；(4) 注意检验最值点是否在取值范围内。底选坐标轴上的边，高用函数纵坐标表示，是简化计算的关键。</p><hr><h2 id="案例-10-一次函数与几何综合压轴-⭐⭐⭐⭐" tabindex="-1">案例 10：一次函数与几何综合压轴 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-10-一次函数与几何综合压轴-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 10：一次函数与几何综合压轴 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+x+'" alt="案例10示意图"></p><p><strong>【题目】</strong> （广州中考风格压轴）如图，直线 y = −(3/4)x + 6 与 x 轴交于点 A，与 y 轴交于点 B，点 C(0, 2)。</p><p>（1）求点 A 的坐标及直线 AB 与坐标轴围成的三角形面积；</p><p>（2）点 P 在直线 AB 上，且 ▵APC 是以 AC 为底的等腰三角形，求点 P 的坐标；</p><p>（3）点 P 在直线 AB 上运动，连接 PC，当 ▵APC 面积最大时，求点 P 的坐标及最大面积。</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 令 y = 0：−(3/4)x + 6 = 0，x = 8。A(8, 0)。</p><p>令 x = 0：y = 6。B(0, 6)。</p><p>S▵OAB; = 1/2 × OA × OB = 1/2 × 8 × 6 = 24。</p><p><strong>答：A(8, 0)，S▵OAB = 24</strong></p><p><strong>（2）</strong> AC = √((8−0)² + (0−2)²) = √(64+4) = √68 = 2√17。</p><p>▵APC 以 AC 为底等腰，即 AP = CP。</p><p>设 P(m, −3m/4 + 6)（0 ≤ m ≤ 8）。</p><p>AP² = (m−8)² + (−3m/4+6)²</p><p>CP² = m² + (−3m/4+6−2)² = m² + (−3m/4+4)²</p><p>令 AP² = CP²：</p><p>(m−8)² + (−3m/4+6)² = m² + (−3m/4+4)²</p><p>展开左边：(m² − 16m + 64) + (9m²/16 − 9m + 36)</p><p>= m² − 16m + 64 + 9m²/16 − 9m + 36</p><p>= 25m²/16 − 25m + 100</p><p>展开右边：m² + (9m²/16 − 6m + 16)</p><p>= m² + 9m²/16 − 6m + 16</p><p>= 25m²/16 − 6m + 16</p><p>令左右相等：</p><p>25m²/16 − 25m + 100 = 25m²/16 − 6m + 16</p><p>−25m + 100 = −6m + 16</p><p>−19m = −84</p><p>m = 84/19</p><p>y = −3/4 × 84/19 + 6 = −63/19 + 114/19 = 51/19</p><p>验证：0 ≤ 84/19 ≈ 4.4 ≤ 8 ✓</p><p><strong>答：P(84/19, 51/19)</strong></p><p><strong>（3）</strong> ▵APC 以 AC 为底，AC = 2√17。</p><p>P 到 AC 的距离最大时，面积最大。</p><p>AC 所在直线：过 A(8, 0) 和 C(0, 2)，斜率 = (2−0)/(0−8) = −1/4。</p><p>直线 AC：y − 0 = (−1/4)(x − 8)，即 y = −x/4 + 2，即 x/4 + y − 2 = 0。</p><p>设 P(m, −3m/4 + 6)，P 到直线 AC 的距离：</p><p>d = |m/4 + (−3m/4+6) − 2| / √(1/16 + 1) = |m/4 − 3m/4 + 4| / √(17/16) = |−m/2 + 4| × 4/√17</p><p>= |4 − m/2| × 4/√17</p><p>当 0 ≤ m ≤ 8 时，4 − m/2 ≥ 0，所以：</p><p>d = (4 − m/2) × 4/√17 = (16 − 2m)/√17</p><p>d 在 m = 0 时取最大值 16/√17。</p><p>但需验证 P(0, 6) = B 点是否在直线 AB 上 ✓。</p><p>S▵APC; = 1/2 × AC × d = 1/2 × 2√17 × (16 − 2m)/√17 = 16 − 2m</p><p>当 m = 0 时，S&amp;submax; = 16。</p><p>即 P 与 B 重合时面积最大。</p><p>验证：S▵ABC; = 1/2 × AC × B到AC距离。AC = 2√17，B(0,6) 到 AC：d = |0/4 + 6 − 2|/√(17/16) = 4 × 4/√17 = 16/√17。S = 1/2 × 2√17 × 16/√17 = 16 ✓。</p><p><strong>答：P(0, 6)（即 B 点）时面积最大，最大面积为 16</strong></p><p><strong>【方法提炼】</strong> 一次函数与几何综合压轴题是广州中考的“终极BOSS”。核心方法体系：(1) 坐标法是基础工具，将几何问题代数化；(2) 等腰三角形问题用距离公式列方程；(3) 面积最值转化为点到直线距离的最值；(4) 点到直线距离公式 d = |Ax&amp;sub0; + By&amp;sub0; + C|/√(A² + B²) 是解题利器；(5) 注意检验最值点是否满足条件（在指定线段上）。广州中考压轴题往往2–3问，第(1)问送分，第(2)问中等，第(3)问拉开差距。</p><hr><h2 id="方法总结" tabindex="-1">方法总结 <a class="header-anchor" href="#方法总结" aria-label="Permalink to &quot;方法总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>题型</th><th>核心方法</th><th>易错点</th><th>难度</th></tr></thead><tbody><tr><td>求解析式</td><td>待定系数法，代入两点列方程组</td><td>计算错误，遗漏验证</td><td>⭐</td></tr><tr><td>图象与性质</td><td>k 决定增减性，b 决定截距，k·b 判定象限</td><td>混淆 k、b 符号与象限的关系</td><td>⭐</td></tr><tr><td>函数与不等式</td><td>交点分界，图象上大下小</td><td>不等号方向弄反</td><td>⭐⭐</td></tr><tr><td>行程应用</td><td>路程 = 速度 × 时间，注意方向</td><td>自变量取值范围遗漏</td><td>⭐⭐</td></tr><tr><td>利润应用</td><td>利润 = 收入 − 成本，不等式求解</td><td>盈亏平衡点理解错误</td><td>⭐⭐</td></tr><tr><td>三角形面积</td><td>选坐标轴上的边为底，高 = 纵/横坐标绝对值</td><td>绝对值分类讨论遗漏</td><td>⭐⭐⭐</td></tr><tr><td>分段函数</td><td>准确分段，每段独立建模</td><td>分段点归属不清，范围标注遗漏</td><td>⭐⭐⭐</td></tr><tr><td>方案设计</td><td>比较两个一次函数大小，求交点临界值</td><td>交点两侧方案选择弄反</td><td>⭐⭐⭐</td></tr><tr><td>动点面积最值</td><td>面积 S 用参数 t 表示，配方求二次函数最值</td><td>未检验最值点是否在取值范围内</td><td>⭐⭐⭐⭐</td></tr><tr><td>几何综合压轴</td><td>坐标法 + 距离公式 + 点到直线距离 + 分类讨论</td><td>计算量大需耐心，等腰三角形漏解</td><td>⭐⭐⭐⭐</td></tr></tbody></table><h3 id="解题通法口诀" tabindex="-1">解题通法口诀 <a class="header-anchor" href="#解题通法口诀" aria-label="Permalink to &quot;解题通法口诀&quot;">​</a></h3><blockquote><p><strong>一次函数解题五步法：</strong></p><ol><li><strong>设</strong> —— 设解析式 y = kx + b（或设动点参数 t）</li><li><strong>代</strong> —— 代入已知条件，列方程（组）</li><li><strong>解</strong> —— 解方程，求 k、b 或参数值</li><li><strong>验</strong> —— 验证解的合理性（范围、意义）</li><li><strong>答</strong> —— 规范作答，注意单位</li></ol></blockquote><blockquote><p><strong>面积问题三原则：</strong></p><ul><li>底选坐标轴上的边，高用坐标表示</li><li>遇绝对值必分类讨论</li><li>最值问题配方转化</li></ul></blockquote><blockquote><p><strong>广州中考一次函数考情：</strong></p><ul><li>基础题（选择/填空）：求解析式、判断象限，2–3 分</li><li>中档题（解答题前段）：实际应用、方案设计，6–8 分</li><li>压轴题（解答题最后）：一次函数 + 动点 + 几何综合，10–12 分</li><li>高频组合：一次函数 × 等腰三角形 × 面积最值 × 分类讨论</li></ul></blockquote>',244)])])}const R=t(b,[["render",h]]);export{S as __pageData,R as default};
